module adder_32bit
(
    input [32:1] A,
    input [32:1] B,
    output [32:1] S,
    output C32
);

wire [31:0] sum1, sum2;
wire carry1;

// Instantiate two 16-bit adders
wire [15:0] A_lo, B_lo, A_hi, B_hi;
wire [16:0] sum_lo, sum_hi;

assign A_lo = A[15:0];
assign B_lo = B[15:0];
assign A_hi = A[31:16];
assign B_hi = B[31:16];

// 16-bit adder for lower bits
assign {carry1, sum_lo[15:0]} = A_lo + B_lo;
// 16-bit adder for upper bits
assign {sum_hi[15:0]} = A_hi + B_hi + carry1;
assign sum_hi[16] = carry1; // Carry-out from upper bits

// Concatenate the results
assign sum2 = {sum_hi[15:0], sum_lo[15:0]};
assign S = sum2;
assign C32 = sum_hi[16];

endmodule
